}

public boolean equals(Object obj) {
    if (this == obj) {
        return true;
    }

    if (obj == null || getClass() != obj.getClass()) {
        return false;
    }

    @SuppressWarnings("unchecked")
    SynchronizedGraph<Object, Object> other = (SynchronizedGraph<Object, Object>) obj;
    return eq(g, other.g);
}

